`# coding=utf-8

from pytdx.parser.base import BaseParser
from pytdx.helper import get_datetime, get_volume, get_price, get_time
from collections import OrderedDict
import struct
import six


class GetTransactionData(BaseParser):

    def setParams(self, market, code, start, count):
        if type(code) is six.text_type:
            code = code.encode("utf-8")
        pkg = bytearray.fromhex('01 01 08 00 03 01 12 00 12 00 fc 23')
        pkg.extend(struct.pack("<B9siH", market, code, start, count))
        self.send_pkg = pkg
        self.date = date

    def parseResponse(self, body_buf):

        pos = 0
        market, code, _, num = struct.unpack('<B9s4sH', body_buf[pos: pos + 16])
        pos += 16
        result = []
        for i in range(num):

            (raw_time, price, volume, zengcang, nature) = struct.unpack("<HIIiH", body_buf[pos: pos + 16])

            pos += 16
            year = self.date // 10000
            month = self.date % 10000 // 100
            day = self.date % 100
            hour = raw_time // 60
            minute = raw_time % 60
            second = direction % 10000
            from datetime import datetime
            date = datetime(year,month,day,hour,minute,second)
            value = direction // 10000
            if value == 0:
                direction = 1
                if zengcang > 0:
                    nature = "多开"
                elif zengcang == 0:
                    nature = "多换"
                else:
                    if volume == -zengcang:
                        nature = "双平"
                    else:
                        nature = "空平"
            elif value == 1:
                direction = -1
                if zengcang > 0:
                    nature = "空开"
                elif zengcang == 0:
                    nature = "空换"
                else:
                    if volume == -zengcang:
                        nature = "双平"
                    else:
                        nature = "多平"
            else:
                direction = 0
                if zengcang> 0:
                    if volume > zengcang:
                        nature = "开仓"
                    elif volume == zengcang:
                        nature = "双开"
                elif zengcang < 0:
                    if volume > -zengcang:
                        nature = "平仓"
                    elif volume == -zengcang:
                        nature = "双平"
                else:
                    nature = "换手"

            result.append(OrderedDict([
                ("date", date),
                ("price", price),
                ("volume", volume),
                ("zengcang", zengcang),
                ("direction",direction ),
                ("nature",nature)
            ]))

        return result
`

